## Summary of React Context Pattern Analysis

I've searched the `/apps/v4/registry/bases` directory and found **8 components that implement React.createContext** (not just wrapping base-ui primitives). Here are the key findings:

### Components with Custom React Context:
1. **ToggleGroup** (both base and radix versions)
2. **Sidebar** (both base and radix versions)
3. **Carousel** (both base and radix versions)
4. **Chart** (both base and radix versions)

---

## Pattern Analysis: 2 Detailed Examples

### 1. **ToggleGroup Context Pattern** (Simpler)
**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775473441949-2j8kvu/apps/v4/registry/bases/radix/ui/toggle-group.tsx`

```typescript
const ToggleGroupContext = React.createContext<
  VariantProps<typeof toggleVariants> & {
    spacing?: number
    orientation?: "horizontal" | "vertical"
  }
>({
  size: "default",
  variant: "default",
  spacing: 0,
  orientation: "horizontal",
})

function useContext() {
  const context = React.useContext(ToggleGroupContext)
  // No error throwing, just returns context
}

// Provider in root component:
<ToggleGroupPrimitive.Root {...props}>
  <ToggleGroupContext.Provider value={{ variant, size, spacing, orientation }}>
    {children}
  </ToggleGroupContext.Provider>
</ToggleGroupPrimitive.Root>

// Child component usage:
function ToggleGroupItem({...}) {
  const context = React.useContext(ToggleGroupContext)
  return (
    <TogglePrimitive
      data-variant={context.variant || variant}
      data-size={context.size || size}
      {...props}
    />
  )
}
```

**Key Pattern:**
- Simple context with default values
- Context provides styling config (variant, size, spacing, orientation)
- Child items read from context and fallback to their own props
- No custom hook with error checking (optional approach)

---

### 2. **Sidebar Context Pattern** (More Complex)
**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775473441949-2j8kvu/apps/v4/registry/bases/radix/ui/sidebar.tsx`

```typescript
type SidebarContextProps = {
  state: "expanded" | "collapsed"
  open: boolean
  setOpen: (open: boolean) => void
  openMobile: boolean
  setOpenMobile: (open: boolean) => void
  isMobile: boolean
  toggleSidebar: () => void
}

const SidebarContext = React.createContext<SidebarContextProps | null>(null)

function useSidebar() {
  const context = React.useContext(SidebarContext)
  if (!context) {
    throw new Error("useSidebar must be used within a SidebarProvider.")
  }
  return context
}

function SidebarProvider({
  defaultOpen = true,
  open: openProp,
  onOpenChange: setOpenProp,
  ...props
}) {
  const isMobile = useIsMobile()
  const [openMobile, setOpenMobile] = React.useState(false)
  const [_open, _setOpen] = React.useState(defaultOpen)
  const open = openProp ?? _open
  const setOpen = React.useCallback(
    (value: boolean | ((value: boolean) => boolean)) => {
      const openState = typeof value === "function" ? value(open) : value
      if (setOpenProp) {
        setOpenProp(openState)
      } else {
        _setOpen(openState)
      }
      document.cookie = `${SIDEBAR_COOKIE_NAME}=${openState}; path=/; max-age=${SIDEBAR_COOKIE_MAX_AGE}`
    },
    [setOpenProp, open]
  )

  const toggleSidebar = React.useCallback(() => {
    return isMobile ? setOpenMobile((open) => !open) : setOpen((open) => !open)
  }, [isMobile, setOpen, setOpenMobile])

  React.useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === SIDEBAR_KEYBOARD_SHORTCUT && (event.metaKey || event.ctrlKey)) {
        event.preventDefault()
        toggleSidebar()
      }
    }
    window.addEventListener("keydown", handleKeyDown)
    return () => window.removeEventListener("keydown", handleKeyDown)
  }, [toggleSidebar])

  const state = open ? "expanded" : "collapsed"
  const contextValue = React.useMemo<SidebarContextProps>(
    () => ({ state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar }),
    [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar]
  )

  return (
    <SidebarContext.Provider value={contextValue}>
      <div {...props}>{children}</div>
    </SidebarContext.Provider>
  )
}

// Child components use: const { isMobile, state, toggleSidebar } = useSidebar()
```

**Key Pattern:**
- Complex context with state management (controlled + internal state)
- Explicit `useSidebar()` hook with error throwing
- Context has null default, hook enforces usage within Provider
- Memoized context value for performance
- Keyboard shortcuts and event listeners in Provider
- Cookie persistence for sidebar state
- Responsive behavior detection with `useIsMobile()` hook

---

## Tabs & Separator Components

### **Tabs** - Orientation Handling
**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775473441949-2j8kvu/apps/v4/registry/bases/radix/ui/tabs.tsx`

```typescript
