  className,
  orientation = "horizontal",
  decorative = true,
  ...props
}: React.ComponentProps<typeof SeparatorPrimitive.Root>) {
  return (
    <SeparatorPrimitive.Root
      data-slot="separator"
      decorative={decorative}
      orientation={orientation}
      className={cn(
        "shrink-0 bg-border data-horizontal:h-px data-horizontal:w-full data-vertical:w-px data-vertical:self-stretch",
        className
      )}
      {...props}
    />
  )
}
```

**Key Patterns:**
- Wraps radix-ui primitive with data-slot attribute
- Orientation styling via Tailwind data selectors
- No context needed—simple wrapper

---

## Recommendations for Your Stepper Component

Based on these patterns, for a **Stepper compound component**, I recommend:

1. **Use the Sidebar pattern** (complex state + hook) if Stepper needs:
   - Current step state
   - Validation state
   - Callbacks for step changes
   - Multiple interactions between sub-components

2. **Key implementation details:**
   ```typescript
   type StepperContextProps = {
     currentStep: number
     totalSteps: number
     setCurrentStep: (step: number) => void
     canGoNext: boolean
     canGoPrev: boolean
     orientation?: "horizontal" | "vertical"
   }

   const StepperContext = React.createContext<StepperContextProps | null>(null)

   function useStepper() {
     const context = React.useContext(StepperContext)
     if (!context) {
       throw new Error("useStepper must be used within a <Stepper />")
     }
     return context
   }
   ```

3. **Use data attributes** for orientation styling (like Tabs)
4. **Memoize context values** to prevent unnecessary re-renders
5. **Support both controlled and uncontrolled modes** (like Sidebar)

