I now have everything needed to produce the complete implementation plan. Here it is:

---

## Complete Implementation Plan: Stepper Compound Component

### Overview

Eight files total: 4 new files, 4 registry insertions. The two `stepper.tsx` files differ only in their `cn` import path. The two `stepper-example.tsx` files differ only in their `@/registry/bases/{base}/...` import paths throughout.

---

## 1. `apps/v4/registry/bases/radix/ui/stepper.tsx`

This is the canonical source. The base version is identical except `@/registry/bases/radix/` becomes `@/registry/bases/base/`.

```tsx
"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"

// ─── Context Types ───────────────────────────────────────────────────────────

type StepperContextValue = {
  value: number
  onValueChange: (value: number) => void
  orientation: "horizontal" | "vertical"
}

type StepperItemContextValue = {
  step: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

// ─── Contexts ────────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a Stepper.")
  }
  return context
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a StepperItem.")
  }
  return context
}

// ─── Stepper (Root) ──────────────────────────────────────────────────────────

function Stepper({
  className,
  value: valueProp,
  defaultValue = 1,
  onValueChange,
  orientation = "horizontal",
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: number
  defaultValue?: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const value = valueProp ?? internalValue

  const handleValueChange = React.useCallback(
    (next: number) => {
      if (valueProp === undefined) {
        setInternalValue(next)
      }
      onValueChange?.(next)
    },
    [valueProp, onValueChange]
  )

  const contextValue = React.useMemo(
    () => ({ value, onValueChange: handleValueChange, orientation }),
    [value, handleValueChange, orientation]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex",
          orientation === "horizontal" ? "flex-row items-center" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

function StepperItem({
  className,
  step,
  disabled = false,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}) {
  const { value } = useStepper()

  const isActive = value === step
  const isCompleted = value > step
  const isDisabled = disabled

  const itemContextValue = React.useMemo(
    () => ({ step, isActive, isCompleted, isDisabled }),
    [step, isActive, isCompleted, isDisabled]
  )

  return (
    <StepperItemContext.Provider value={itemContextValue}>
      <div
        data-slot="stepper-item"
        data-active={isActive || undefined}
        data-completed={isCompleted || undefined}
        data-disabled={isDisabled || undefined}
        className={cn(
          "cn-stepper-item flex items-center gap-2",
          "group-data-vertical/stepper:flex-col group-data-vertical/stepper:items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, isDisabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      disabled={isDisabled}
      onClick={() => {
        if (!isDisabled) {
          onValueChange(step)
        }
      }}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-2 outline-none disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperTitle ────────────────────────────────────────────────────────────

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("cn-stepper-title text-sm font-medium", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-sm text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "cn-stepper-separator bg-border",
        "group-data-horizontal/stepper:h-px group-data-horizontal/stepper:flex-1",
        "group-data-vertical/stepper:w-px group-data-vertical/stepper:flex-1 group-data-vertical/stepper:self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ────────────────────────────────────────────────────────────

function StepperPanel({
  className,
  step,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { value } = useStepper()

  if (value !== step) return null

  return (
    <div
      data-slot="stepper-panel"
      className={cn("cn-stepper-panel", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ─── Exports ─────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
}
```

