## 2. `apps/v4/registry/bases/radix/examples/stepper-example.tsx`

```tsx
"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/radix/components/example"
import { Button } from "@/registry/bases/radix/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/bases/radix/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper>
      <StepperBasic />
      <StepperWithDescription />
      <StepperVertical />
      <StepperWithContent />
      <StepperDisabledStep />
    </ExampleWrapper>
  )
}

function StepperBasic() {
  return (
    <Example title="Basic">
      <Stepper defaultValue={1} className="w-full">
        <StepperItem step={1}>
          <StepperTrigger>
            <StepperTitle>Account</StepperTitle>
          </StepperTrigger>
        </StepperItem>
        <StepperSeparator />
        <StepperItem step={2}>
          <StepperTrigger>
            <StepperTitle>Profile</StepperTitle>
          </StepperTrigger>
        </StepperItem>
        <StepperSeparator />
        <StepperItem step={3}>
          <StepperTrigger>
            <StepperTitle>Review</StepperTitle>
          </StepperTrigger>
        </StepperItem>
      </Stepper>
    </Example>
  )
}

function StepperWithDescription() {
  return (
    <Example title="With Description">
      <Stepper defaultValue={2} className="w-full">
        <StepperItem step={1}>
          <StepperTrigger>
            <div className="flex flex-col items-start">
              <StepperTitle>Account</StepperTitle>
              <StepperDescription>Create your account</StepperDescription>
            </div>
          </StepperTrigger>
        </StepperItem>
        <StepperSeparator />
        <StepperItem step={2}>
          <StepperTrigger>
            <div className="flex flex-col items-start">
              <StepperTitle>Profile</StepperTitle>
              <StepperDescription>Set up your profile</StepperDescription>
            </div>
          </StepperTrigger>
        </StepperItem>
        <StepperSeparator />
        <StepperItem step={3}>
          <StepperTrigger>
            <div className="flex flex-col items-start">
              <StepperTitle>Review</StepperTitle>
              <StepperDescription>Confirm your details</StepperDescription>
            </div>
          </StepperTrigger>
        </StepperItem>
      </Stepper>
    </Example>
  )
}

function StepperVertical() {
  return (
    <Example title="Vertical">
      <Stepper defaultValue={1} orientation="vertical">
        <StepperItem step={1}>
          <StepperTrigger>
            <StepperTitle>Account</StepperTitle>
          </StepperTrigger>
        </StepperItem>
        <StepperSeparator />
        <StepperItem step={2}>
          <StepperTrigger>
            <StepperTitle>Profile</StepperTitle>
          </StepperTrigger>
        </StepperItem>
        <StepperSeparator />
        <StepperItem step={3}>
          <StepperTrigger>
            <StepperTitle>Review</StepperTitle>
          </StepperTrigger>
        </StepperItem>
      </Stepper>
    </Example>
  )
}

function StepperWithContent() {
  const [step, setStep] = React.useState(1)
  const totalSteps = 3

  return (
    <Example title="With Content" containerClassName="col-span-full">
      <Stepper
        value={step}
        onValueChange={setStep}
        className="w-full"
      >
        <StepperItem step={1}>
          <StepperTrigger>
            <StepperTitle>Account</StepperTitle>
          </StepperTrigger>
        </StepperItem>
        <StepperSeparator />
        <StepperItem step={2}>
          <StepperTrigger>
            <StepperTitle>Profile</StepperTitle>
          </StepperTrigger>
        </StepperItem>
        <StepperSeparator />
        <StepperItem step={3}>
          <StepperTrigger>
            <StepperTitle>Review</StepperTitle>
          </StepperTrigger>
        </StepperItem>

        <StepperPanel step={1} className="mt-4 w-full">
          <p className="text-sm text-muted-foreground">
            Enter your email address and choose a secure password to get
            started.
          </p>
        </StepperPanel>
        <StepperPanel step={2} className="mt-4 w-full">
          <p className="text-sm text-muted-foreground">
            Add your name, avatar, and a short bio so others can find you.
          </p>
        </StepperPanel>
        <StepperPanel step={3} className="mt-4 w-full">
          <p className="text-sm text-muted-foreground">
            Review your information before submitting. You can go back to make
            changes.
          </p>
        </StepperPanel>
      </Stepper>

      <div className="mt-4 flex w-full items-center justify-between gap-2">
        <Button
          variant="outline"
          size="sm"
          disabled={step <= 1}
          onClick={() => setStep((s) => Math.max(1, s - 1))}
        >
          Back
        </Button>
        <Button
          size="sm"
          disabled={step >= totalSteps}
          onClick={() => setStep((s) => Math.min(totalSteps, s + 1))}
        >
          {step === totalSteps ? "Submit" : "Next"}
        </Button>
      </div>
    </Example>
  )
}

function StepperDisabledStep() {
  return (
    <Example title="Disabled Step">
      <Stepper defaultValue={1} className="w-full">
        <StepperItem step={1}>
          <StepperTrigger>
            <StepperTitle>Account</StepperTitle>
          </StepperTrigger>
        </StepperItem>
        <StepperSeparator />
        <StepperItem step={2} disabled>
          <StepperTrigger>
            <StepperTitle>Profile</StepperTitle>
          </StepperTrigger>
        </StepperItem>
        <StepperSeparator />
        <StepperItem step={3}>
          <StepperTrigger>
            <StepperTitle>Review</StepperTitle>
          </StepperTrigger>
        </StepperItem>
      </Stepper>
    </Example>
  )
}
